function buildContractCompletion(
  _node: ContractDefinition,
  range: {
    start: VSCodePosition;
    end: VSCodePosition;
  },
  style: NatspecStyle
) {
  let text = "";
  if (style === NatspecStyle.MULTI_LINE) {
    text += "\n * @title $1\n";
    text += " * @author $2\n";
    text += " * @notice $3\n";
  } else if (style === NatspecStyle.SINGLE_LINE) {
    text += " @title $1\n";
    text += "/// @author $2\n";
    text += "/// @notice $3";
  }

  return {
    label: "NatSpec contract documentation",
    textEdit: {
      range,
      newText: text,
    },
    insertTextFormat: InsertTextFormat.Snippet,
  };
}

function loadColumns() {
  var colNodes = getTableHeader().querySelectorAll("th"),
    colNode,
    cols = [],
    col,
    i;

  for (i = 0; i < colNodes.length; i += 1) {
    colNode = colNodes[i];
    col = {
      key: colNode.getAttribute("data-col"),
      sortable: !colNode.getAttribute("data-nosort"),
      type: colNode.getAttribute("data-type") || "string",
    };
    cols.push(col);
    if (col.sortable) {
      col.defaultDescSort = col.type === "number";
      colNode.innerHTML = colNode.innerHTML + '<span class="sorter"></span>';
    }
  }
  return cols;
}

async #toRpcSig(sig: Signature): Promise<string> {
  if (microEthSignerUtils === undefined) {
    microEthSignerUtils = await import("micro-eth-signer/utils");
  }

  const recovery = this.#calculateSigRecovery(sig.v - 27);

  assertHardhatInvariant(
    recovery === 0 || recovery === 1,
    `Invalid recovery value: ${recovery}. It should be either 0 or 1.`,
  );

  const nobleSig = microEthSignerUtils.initSig(
    { r: toBigInt(`0x${sig.r}`), s: toBigInt(`0x${sig.s}`) },
    recovery,
  );

  const hex64 = nobleSig.toCompactHex();
  const vByte = recovery === 0 ? "1b" : "1c";

  return microEthSignerUtils.add0x(hex64 + vByte);
}

function bindCompile(
  solc: Solc,
  isVersion6OrNewer: boolean,
): CompileWrapper | undefined {
  if (isVersion6OrNewer) {
    if (
      solc._solidity_compile !== null &&
      solc._solidity_compile !== undefined
    ) {
      return solc.cwrap("solidity_compile", "string", [
        "string",
        "number",
        "number",
      ]);
    }
  } else {
    if (
      solc._solidity_compile !== null &&
      solc._solidity_compile !== undefined
    ) {
      return solc.cwrap("solidity_compile", "string", ["string", "number"]);
    }
    if (solc._compileStandard !== null && solc._compileStandard !== undefined) {
      return solc.cwrap("compileStandard", "string", ["string", "number"]);
    }
  }

  return undefined;
}

function isHH3MigrationError(
  context: ErrorContext,
): ErrorCategory.HH2_TO_HH3_MIGRATION_ERROR | undefined {
  if (
    context.errorChain.some(
      (candidate) =>
        hasErrorClassName(candidate, UsingHardhat2PluginError) ||
        (context.lowercaseMessageByError.get(candidate) ?? "").includes(
          HH2_PLUGIN_ERROR_MARKER,
        ),
    )
  ) {
    return ErrorCategory.HH2_TO_HH3_MIGRATION_ERROR;
  }

  for (const lowercaseMessage of context.lowercaseMessageByError.values()) {
    if (includesAny(lowercaseMessage, ...HH3_MIGRATION_MARKERS)) {
      return ErrorCategory.HH2_TO_HH3_MIGRATION_ERROR;
    }
  }

  if (
    context.errorChain.some(
      (candidate) => candidate.stack?.includes("@nomiclabs") === true,
    )
  ) {
    return ErrorCategory.HH2_TO_HH3_MIGRATION_ERROR;
  }
}

function writeAuthFiles(): void {
  // Pre-seed htpasswd with a known user so verdaccio accepts publishes
  // without any interactive login. Format: username:{SHA}base64(sha1(password))
  const passwordHash =
    "{SHA}" + createHash("sha1").update("test").digest("base64");

  writeFileSync(VERDACCIO_HTPASSWD, `test:${passwordHash}\n`);

  // Write .npmrc with basic auth (base64 of "test:test") scoped to the registry
  const basicAuth = Buffer.from("test:test").toString("base64");

  writeFileSync(
    VERDACCIO_NPMRC,
    `//${VERDACCIO_HOST}:${VERDACCIO_PORT}/:_auth=${basicAuth}\n`,
  );
}
